patch:
diff --git a/llvm/lib/Transforms/Scalar/EarlyCSE.cpp b/llvm/lib/Transforms/Scalar/EarlyCSE.cpp
index 09cb2f4cb010..24fdb915c089 100644
--- a/llvm/lib/Transforms/Scalar/EarlyCSE.cpp
+++ b/llvm/lib/Transforms/Scalar/EarlyCSE.cpp
@@ -351,6 +351,10 @@ unsigned DenseMapInfo<SimpleValue>::getHashValue(SimpleValue Val) {
   return getHashValueImpl(Val);
 }

+static bool canIntersectAttributes(const CallBase *LHS, const CallBase *RHS) {
+  return LHS->getAttributes().intersectWith(LHS->getContext(),
+                                            RHS->getAttributes()).has_value();
+}
 static bool isEqualImpl(SimpleValue LHS, SimpleValue RHS) {
   Instruction *LHSI = LHS.Inst, *RHSI = RHS.Inst;

@@ -397,6 +401,8 @@ static bool isEqualImpl(SimpleValue LHS, SimpleValue RHS) {
   auto *RII = dyn_cast<IntrinsicInst>(RHSI);
   if (LII && RII && LII->getIntrinsicID() == RII->getIntrinsicID() &&
       LII->isCommutative() && LII->arg_size() >= 2) {
+    if (!canIntersectAttributes(LII, RII))
+      return false;
     return LII->getArgOperand(0) == RII->getArgOperand(1) &&
            LII->getArgOperand(1) == RII->getArgOperand(0) &&
            std::equal(LII->arg_begin() + 2, LII->arg_end(),

